import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { checkLocationPermission, requestLocationPermission } from '../services/locationService';
import { AlertCircle, MapPin } from 'lucide-react';

/**
 * Location Permission Guard
 * Ensures location is enabled before allowing app access
 * Auto-exits if location becomes disabled
 */
export const LocationGuard = ({ children }) => {
  const navigate = useNavigate();
  const [locationAllowed, setLocationAllowed] = useState(true);
  const [showPrompt, setShowPrompt] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Check location permission on mount and periodically
  useEffect(() => {
    const checkPermission = async () => {
      try {
        const isAllowed = await checkLocationPermission();
        setLocationAllowed(isAllowed);

        if (!isAllowed) {
          setShowPrompt(true);
          // Try to request permission
          try {
            await requestLocationPermission();
            setLocationAllowed(true);
            setShowPrompt(false);
          } catch (error) {
            console.warn('Location permission denied:', error);
          }
        }
      } catch (error) {
        console.warn('Could not check location permission:', error);
      } finally {
        setIsLoading(false);
      }
    };

    // Initial check
    checkPermission();

    // Periodic check every 5 seconds
    const interval = setInterval(checkPermission, 5000);

    return () => clearInterval(interval);
  }, []);

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-800">
        <div className="text-center space-y-4">
          <MapPin className="animate-pulse mx-auto text-blue-500" size={48} />
          <p className="text-slate-600 dark:text-slate-400">Verifying location access...</p>
        </div>
      </div>
    );
  }

  if (!locationAllowed) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 to-slate-100 dark:from-slate-900 dark:to-slate-800 p-4">
        <div className="bg-white dark:bg-slate-800 rounded-2xl p-8 max-w-md w-full shadow-xl border-2 border-red-200 dark:border-red-900">
          <div className="flex gap-3 mb-6">
            <AlertCircle className="text-red-500 flex-shrink-0" size={32} />
            <div>
              <h1 className="text-2xl font-bold text-slate-900 dark:text-white">Location Required</h1>
              <p className="text-sm text-slate-500 dark:text-slate-400">Cannot access the app</p>
            </div>
          </div>

          <div className="bg-red-50 dark:bg-red-900/20 rounded-lg p-4 mb-6 border border-red-200 dark:border-red-800">
            <p className="text-slate-700 dark:text-slate-300 text-sm">
              This app requires location services to work properly. Please:
            </p>
            <ul className="list-disc list-inside mt-3 text-sm text-slate-600 dark:text-slate-400 space-y-2">
              <li>Enable location permission in your browser</li>
              <li>Allow this website to access your location</li>
              <li>Click "Allow" when prompted</li>
            </ul>
          </div>

          <button
            onClick={() => window.location.reload()}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg transition-colors duration-200"
          >
            Try Again
          </button>

          <button
            onClick={() => navigate('/login')}
            className="w-full mt-2 bg-slate-200 dark:bg-slate-700 hover:bg-slate-300 dark:hover:bg-slate-600 text-slate-900 dark:text-white font-bold py-3 rounded-lg transition-colors duration-200"
          >
            Back to Login
          </button>

          <p className="text-xs text-slate-500 dark:text-slate-500 mt-4 text-center">
            Location helps us provide accurate ambulance and bus tracking services.
          </p>
        </div>
      </div>
    );
  }

  return children;
};

export default LocationGuard;
